public class SharedMutable {
    static class Counter {
        int count = 0;
        void inc() { count++; }
    }
    public static void main(String[] args) {
        Counter c1 = new Counter();
        Counter c2 = c1;       // alias
        c1.inc(); c1.inc();
        c2.inc();
        System.out.println(c1.count);
        System.out.println(c2.count);
        System.out.println(c1 == c2);
    }
}
